// 🔹 Get Domain dynamically
const domain = $('📝 Input: Keyword & Domain').first().json.Domain;

// 🔹 Get Keywords dynamically
let keywords = $input.first().json.output;

// 🛠 Ensure keywords is always an array of clean lines
if (typeof keywords === "string") {
 keywords = keywords
 .split(/\r?\n/) // split ONLY on newlines
 .map(k => k.replace(/^[\s\-•\d.]+/, "").trim()) // remove bullets, numbers, dashes
 .filter(k => k.length > 0);
} else if (!Array.isArray(keywords)) {
 keywords = [keywords];
}

// 🛠 Remove filler text
keywords = keywords.filter(k => 
 !/^keywords related/i.test(k) &&
 !/^these keywords/i.test(k) &&
 !/^let me know/i.test(k)
);

// 🔹 Join all keywords into one string with numbering
const keywordString = keywords.map((k, i) => ${i + 1}. ${k}).join("\n");

// 🔹 Return as single row
return [
 {
 json: {
 "Domain": domain,
 "Keywords": keywordString
 }
 }
];

