// Step 1: Get SERP data directly
const serpData = $input.first().json;

// Step 2: Extract keyword & domain
const keyword = $input.first().json.search_parameters.q;
const domainToCheck = $('📝 Input: Keyword & Domain').first().json.Domain;

// Step 3: Extract organic results
const organicResults = Array.isArray(serpData.organic_results) ? serpData.organic_results : [];

// Step 4: Find ranking
let position = 999;
let rankingUrl = "Not found";

function normalizeUrl(url) {
 if (!url) return "";
 return url.replace(/^https?:\/\/(www\.)?/, "").replace(/\/$/, "");
}

const targetDomainNormalized = normalizeUrl(domainToCheck);

for (let i = 0; i < organicResults.length; i++) {
 const result = organicResults[i];
 if (result?.link) {
 const resultDomain = normalizeUrl(result.link);
 if (resultDomain.includes(targetDomainNormalized)) {
 position = i + 1;
 rankingUrl = result.link;
 break;
 }
 }
}

// Step 5: Return result
return [
 {
 json: {
 Keyword: keyword,
 Domain: domainToCheck,
 Position: position,
 Ranking_URL: rankingUrl,
 },
 },
];

